/**
 * Curated font registry — a broad set of the strongest, ATS-safe resume
 * typefaces. All families are SELF-HOSTED: the woff2
 * files live in public/fonts/ and their @font-face rules are in
 * src/styles/fonts.css (generated by scripts/fetch-fonts.cjs). The app makes
 * ZERO external font requests — nothing is fetched from Google. Because the live
 * preview and the native print render in the SAME browser, the printed PDF is
 * byte-identical to the preview.
 */

export type FontCategory = 'sans' | 'serif' | 'mono' | 'display' | 'handwriting'

export interface FontDef {
  /** Display + CSS family name */
  name: string
  category: FontCategory
  /** Google Fonts family query (defaults to name) */
  family?: string
  /** Weights to request */
  weights?: number[]
  /** Italic axis available */
  italic?: boolean
  /** CSS fallback stack */
  fallback?: string
}

