const FALLBACKS: Record<FontCategory, string> = {
  sans: 'ui-sans-serif, system-ui, -apple-system, sans-serif',
  serif: 'ui-serif, Georgia, Cambria, "Times New Roman", serif',
  mono: 'ui-monospace, SFMono-Regular, Menlo, monospace',
  display: 'ui-sans-serif, system-ui, sans-serif',
  handwriting: 'cursive',
}

export const FONT_MAP: Record<string, FontDef> = Object.fromEntries(FONTS.map((f) => [f.name, f]))

export function fontStack(name?: string): string {
  if (!name) return FALLBACKS.sans
  const def = FONT_MAP[name]
  const fb = def ? def.fallback ?? FALLBACKS[def.category] : FALLBACKS.sans
  return `"${name}", ${fb}`
}

/**
 * No-op kept for API compatibility. Fonts are self-hosted and their @font-face
 * rules ship in the bundle (src/styles/fonts.css), so there is nothing to inject
 * — the browser lazily fetches the (same-origin, service-worker-precached) woff2
 * on first use. Safe to call on every render.
 */
export function ensureFont(_name?: string): void {
  /* fonts are bundled and always available — nothing to do */
}

/**
 * Resolve only once the requested faces are actually rasterizable. The @font-face
 * rules are already registered (bundled CSS), so we just drive `document.fonts.load`
 * for the specific faces and await `fonts.ready`. This guarantees the print/PDF
 * never falls back to a system font.
 */
export async function ensureFontsReady(names: (string | undefined)[]): Promise<void> {
  const real = names.filter((n): n is string => !!n)
  if (typeof document === 'undefined' || !('fonts' in document)) return
  const fonts = (document as Document & { fonts: FontFaceSet }).fonts
  try {
    await Promise.all(
      real.flatMap((n) => [fonts.load(`400 1em "${n}"`), fonts.load(`700 1em "${n}"`)]).map((p) => p.catch(() => undefined))
    )
    await fonts.ready
  } catch {
    /* ignore */
  }
}

export const FONTS_BY_CATEGORY: Record<FontCategory, FontDef[]> = {
  sans: FONTS.filter((f) => f.category === 'sans'),
  serif: FONTS.filter((f) => f.category === 'serif'),
  mono: FONTS.filter((f) => f.category === 'mono'),
  display: FONTS.filter((f) => f.category === 'display'),
  handwriting: FONTS.filter((f) => f.category === 'handwriting'),
}
